"use client";

import { PiggyBank, Receipt, PlusCircle, TrendingDown, AlertCircle } from "lucide-react";
import { motion } from "framer-motion";

export default function ExpensesPage() {
    const expenses = [
        { id: 1, category: "Monumento", description: "Pago Artista Fallero - 20%", amount: 4500.00, date: "2024-02-01" },
        { id: 2, category: "Pirotecnia", description: "Mascletà 18 Marzo", amount: 2500.00, date: "2024-01-20" },
        { id: 3, category: "Casal", description: "Alquiler + Luz", amount: 850.00, date: "2024-02-05" },
        { id: 4, category: "Eventos", description: "Cena Presentación", amount: 1200.00, date: "2024-01-28" },
    ];

    return (
        <motion.div
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.4 }}
            className="space-y-8"
        >
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-foreground flex items-center gap-2">
                        <span className="bg-rose-100 text-rose-600 p-2 rounded-lg dark:bg-rose-900/30">
                            <TrendingDown className="h-6 w-6" />
                        </span>
                        Gastos
                    </h2>
                    <p className="text-muted-foreground mt-1">Control de partidas presupuestarias y pagos.</p>
                </div>
                <div className="flex gap-2">
                    <button className="inline-flex items-center justify-center rounded-xl text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring border border-input bg-background hover:bg-accent hover:text-accent-foreground h-10 px-4 py-2">
                        Presupuesto
                    </button>
                    <button className="inline-flex items-center justify-center rounded-xl text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring bg-rose-600 text-white hover:bg-rose-700 h-10 px-4 py-2 shadow-sm hover:shadow-rose-500/20">
                        <PlusCircle className="mr-2 h-4 w-4" />
                        Registrar Gasto
                    </button>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
                <BudgetCard
                    title="Monumento"
                    budget={55000}
                    spent={25000}
                    color="rose"
                />
                <BudgetCard
                    title="Pirotecnia"
                    budget={12000}
                    spent={3000}
                    color="amber"
                />
                <BudgetCard
                    title="Casal"
                    budget={10000}
                    spent={8400}
                    color="blue"
                    alert
                />
                <BudgetCard
                    title="Eventos"
                    budget={15000}
                    spent={5000}
                    color="emerald"
                />
            </div>

            <div className="bg-card rounded-2xl border border-border/50 shadow-sm overflow-hidden">
                <div className="p-6 border-b border-border/50 flex justify-between items-center">
                    <h3 className="text-lg font-medium leading-6">Últimos Gastos</h3>
                    <button className="text-sm text-primary hover:underline">Ver todo</button>
                </div>
                <div className="relative w-full overflow-auto">
                    <table className="w-full caption-bottom text-sm text-left">
                        <thead className="[&_tr]:border-b bg-muted/30">
                            <tr className="border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted">
                                <th className="h-12 px-6 align-middle font-medium text-muted-foreground">Fecha</th>
                                <th className="h-12 px-6 align-middle font-medium text-muted-foreground">Concepto</th>
                                <th className="h-12 px-6 align-middle font-medium text-muted-foreground">Categoría</th>
                                <th className="h-12 px-6 text-right align-middle font-medium text-muted-foreground">Importe</th>
                                <th className="h-12 px-6 text-right align-middle font-medium text-muted-foreground">Estado</th>
                            </tr>
                        </thead>
                        <tbody className="[&_tr:last-child]:border-0">
                            {expenses.map((e, i) => (
                                <motion.tr
                                    initial={{ opacity: 0, x: -10 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: i * 0.05 }}
                                    key={e.id}
                                    className="border-b transition-colors hover:bg-slate-50/50 dark:hover:bg-slate-800/30 group"
                                >
                                    <td className="p-6 align-middle font-medium text-muted-foreground">{e.date}</td>
                                    <td className="p-6 align-middle font-semibold text-foreground">{e.description}</td>
                                    <td className="p-6 align-middle">
                                        <span className="inline-flex items-center rounded-md bg-slate-100 px-2.5 py-1 text-xs font-semibold text-slate-600 ring-1 ring-inset ring-slate-500/10 dark:bg-slate-400/10 dark:text-slate-400 uppercase tracking-wide">
                                            {e.category}
                                        </span>
                                    </td>
                                    <td className="p-6 align-middle text-right text-rose-600 font-bold tabular-nums">-{e.amount.toLocaleString()} €</td>
                                    <td className="p-6 align-middle text-right">
                                        <span className="inline-flex items-center rounded-full bg-green-50 px-2 py-1 text-xs font-medium text-green-700 ring-1 ring-inset ring-green-600/20">Pagado</span>
                                    </td>
                                </motion.tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </motion.div>
    );
}

function BudgetCard({ title, budget, spent, color, alert }: any) {
    const percentage = Math.round((spent / budget) * 100);
    const colorClasses: Record<string, string> = {
        rose: "bg-rose-500",
        amber: "bg-amber-500",
        blue: "bg-blue-500",
        emerald: "bg-emerald-500",
    };

    return (
        <div className="rounded-2xl border bg-card text-card-foreground shadow-sm p-6 relative overflow-hidden group hover:border-border/80 transition-colors">
            <div className="flex flex-row items-center justify-between space-y-0 pb-2">
                <h3 className="tracking-tight text-sm font-medium text-muted-foreground uppercase">{title}</h3>
                {alert && <AlertCircle className="h-4 w-4 text-rose-500 animate-pulse" />}
            </div>
            <div className="pt-4">
                <div className="flex justify-between items-baseline mb-1">
                    <div className="text-2xl font-bold tracking-tight">{spent.toLocaleString()} €</div>
                    <div className="text-xs text-muted-foreground font-medium">de {budget.toLocaleString()} €</div>
                </div>

                <div className="w-full bg-muted rounded-full h-2.5 overflow-hidden">
                    <div
                        className={`h-2.5 rounded-full ${colorClasses[color]} transition-all duration-1000 ease-out`}
                        style={{ width: `${percentage}%` }}
                    />
                </div>

                <p className="text-xs text-muted-foreground mt-2 flex justify-between">
                    <span>{percentage}% consumido</span>
                    {alert && <span className="text-rose-600 font-bold">¡Atención!</span>}
                </p>
            </div>
        </div>
    )
}
